import{_ as t,o as e,c as r,ag as o}from"./chunks/framework.B4u4rdkN.js";const u=JSON.parse('{"title":"使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide.md","filePath":"guide.md"}'),i={name:"guide.md"};function l(d,a,s,n,h,p){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="使用指南" tabindex="-1">使用指南 <a class="header-anchor" href="#使用指南" aria-label="Permalink to &quot;使用指南&quot;">​</a></h1><h2 id="安装与启动" tabindex="-1">安装与启动 <a class="header-anchor" href="#安装与启动" aria-label="Permalink to &quot;安装与启动&quot;">​</a></h2><p>AppTimer 是一个<strong>便携式应用</strong>，无需安装：</p><ol><li>下载 <code>AppTimer.exe</code></li><li>放到你喜欢的文件夹（建议 <code>D:\\Tools\\AppTimer\\</code>）</li><li>双击运行即可</li></ol><p>首次启动后，程序会自动最小化到系统托盘（右下角图标），在后台静默记录你的程序使用情况。双击托盘图标或右键选择「显示窗口」即可打开主界面。</p><h2 id="界面概览" tabindex="-1">界面概览 <a class="header-anchor" href="#界面概览" aria-label="Permalink to &quot;界面概览&quot;">​</a></h2><p>主界面分为以下几个区域：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>顶部标题栏</td><td>状态指示灯 + 今日追踪时长 + 深色模式开关</td></tr><tr><td>今日使用</td><td>当前日期各程序的使用时长列表，含分类标签和占比</td></tr><tr><td>饼图 + 柱状图</td><td>今日各程序占比饼图 + 近 7 天使用趋势柱状图</td></tr><tr><td>分类&amp;目标</td><td>设置程序分类标签 + 每日使用目标上限</td></tr></tbody></table><h2 id="追踪面板" tabindex="-1">追踪面板 <a class="header-anchor" href="#追踪面板" aria-label="Permalink to &quot;追踪面板&quot;">​</a></h2><p><strong>今日使用</strong>列表实时显示：</p><ul><li><strong>程序</strong>：自动识别的窗口进程名（优先显示软件官方名称）</li><li><strong>分类</strong>：你为该程序设置的标签</li><li><strong>今日</strong>：今天累计使用了多长时间</li><li><strong>累计</strong>：所有历史数据中的总计使用时长</li><li><strong>占比</strong>：该程序占今日总使用时长的百分比</li></ul><div class="tip custom-block"><p class="custom-block-title">闲置检测</p><p>当你离开电脑超过设定的时间阈值（默认 5 分钟），追踪器会自动暂停，不计入使用时长，确保数据准确。</p></div><h2 id="分类标签" tabindex="-1">分类标签 <a class="header-anchor" href="#分类标签" aria-label="Permalink to &quot;分类标签&quot;">​</a></h2><p>在「分类&amp;目标」标签页中：</p><ol><li>左侧列表选择要分类的程序</li><li>右侧下拉框选择分类标签</li><li>可选标签：<strong>工作、学习、娱乐、社交、开发、设计、其他、未分类</strong></li></ol><p>分类后，主面板和报表中都会按分类统计，图表也会按分类着色。</p><h2 id="数据与报表" tabindex="-1">数据与报表 <a class="header-anchor" href="#数据与报表" aria-label="Permalink to &quot;数据与报表&quot;">​</a></h2><h3 id="数据存储" tabindex="-1">数据存储 <a class="header-anchor" href="#数据存储" aria-label="Permalink to &quot;数据存储&quot;">​</a></h3><p>所有数据保存在本地，路径为：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%USERPROFILE%\\AppTimer\\</span></span></code></pre></div><p>按日期子文件夹组织，每天一个 JSON 文件。</p><h3 id="查看历史" tabindex="-1">查看历史 <a class="header-anchor" href="#查看历史" aria-label="Permalink to &quot;查看历史&quot;">​</a></h3><p>主界面下方的历史记录窗格可查看过往数据。</p><h3 id="导出-csv" tabindex="-1">导出 CSV <a class="header-anchor" href="#导出-csv" aria-label="Permalink to &quot;导出 CSV&quot;">​</a></h3><p>点击「导出 CSV」按钮，可选择导出<strong>今日数据</strong>或<strong>累计数据</strong>，生成的文件可在 Excel 中打开分析。</p><h3 id="自动清理" tabindex="-1">自动清理 <a class="header-anchor" href="#自动清理" aria-label="Permalink to &quot;自动清理&quot;">​</a></h3><p>可在设置中配置数据保留天数（默认 90 天），过期数据自动删除，不必担心占用空间。</p><h2 id="设置与自启动" tabindex="-1">设置与自启动 <a class="header-anchor" href="#设置与自启动" aria-label="Permalink to &quot;设置与自启动&quot;">​</a></h2><h3 id="深色模式" tabindex="-1">深色模式 <a class="header-anchor" href="#深色模式" aria-label="Permalink to &quot;深色模式&quot;">​</a></h3><p>窗口右上角的开关可手动切换深色/浅色主题。程序启动时会自动跟随 Windows 系统主题设置。</p><h3 id="开机自启动" tabindex="-1">开机自启动 <a class="header-anchor" href="#开机自启动" aria-label="Permalink to &quot;开机自启动&quot;">​</a></h3><p>勾选「开机自启动」后，AppTimer 会随 Windows 启动自动运行，无需手动打开。</p><h3 id="最小化到托盘" tabindex="-1">最小化到托盘 <a class="header-anchor" href="#最小化到托盘" aria-label="Permalink to &quot;最小化到托盘&quot;">​</a></h3><p>关闭窗口时，程序不会退出，而是最小化到系统托盘继续后台追踪。右键托盘图标可选择「退出」彻底关闭。</p>',34)])])}const b=t(i,[["render",l]]);export{u as __pageData,b as default};
